<script setup lang="ts">
type CountrySelection = {
  id: string;
  name: string;
};

type WorldMapCountryName = (typeof countries)[number];

const props = withDefaults(
  defineProps<{
    countryNames?: readonly WorldMapCountryName[] | null;
    blink?: boolean;
  }>(),
  {
    countryNames: () => [],
    blink: false,
  }
);

const emit = defineEmits<{
  select: [country: CountrySelection];
}>();

const COUNTRY_BASE_CLASSES = [
  "fill-zinc-900/50",
  "stroke-zinc-600",
  "transition-all",
  "duration-200",
  "ease-out",
  "cursor-pointer",
  "hover:fill-zinc-700",
  "focus:outline-none",
];
const COUNTRY_ACTIVE_CLASSES = ["fill-yellow-600!", "stroke-yellow-500!"];

const svgRef = ref<SVGSVGElement | null>(null);
const selectedCountry = ref<CountrySelection | null>(null);
const activeCountryPaths = ref<SVGPathElement[]>([]);
const activeBlinkAnimations = ref<Animation[]>([]);

const getCountryPath = (target: EventTarget | null): SVGPathElement | null => {
  if (!(target instanceof Element)) {
    return null;
  }

  const countryPath = target.closest("path[data-id][data-name]");

  return countryPath instanceof SVGPathElement ? countryPath : null;
};

const extractCountry = (path: SVGPathElement): CountrySelection => {
  return {
    id: path.dataset.id ?? path.id,
    name: path.dataset.name ?? path.id,
  };
};

const normalizeCountryName = (value: string | null | undefined) => {
  return value?.trim().toLocaleLowerCase() ?? "";
};

const findCountryPathsByName = (countryName: string) => {
  const svgElement = svgRef.value;

  if (!svgElement) {
    return [];
  }

  const normalizedCountryName = normalizeCountryName(countryName);

  if (!normalizedCountryName) {
    return [];
  }

  const matchingPaths: SVGPathElement[] = [];

  for (const countryPath of svgElement.querySelectorAll<SVGPathElement>(
    "path[data-id][data-name]"
  )) {
    const pathName = normalizeCountryName(countryPath.dataset.name);
    const pathId = normalizeCountryName(countryPath.dataset.id ?? countryPath.id);

    if (pathName === normalizedCountryName || pathId === normalizedCountryName) {
      matchingPaths.push(countryPath);
    }
  }

  return matchingPaths;
};

const findCountryPathsByPath = (path: SVGPathElement) => {
  return findCountryPathsByName(path.dataset.name ?? path.dataset.id ?? path.id);
};

const findCountryPathsByNames = (countryNames: readonly WorldMapCountryName[]) => {
  const matchingPaths: SVGPathElement[] = [];
  const seenPathIds = new Set<string>();

  for (const countryName of countryNames) {
    for (const countryPath of findCountryPathsByName(countryName)) {
      const pathKey = `${countryPath.dataset.id ?? countryPath.id}:${countryPath.getAttribute("d") ?? ""}`;

      if (seenPathIds.has(pathKey)) {
        continue;
      }

      seenPathIds.add(pathKey);
      matchingPaths.push(countryPath);
    }
  }

  return matchingPaths;
};

const applyBaseCountryStyles = (path: SVGPathElement) => {
  path.classList.add(...COUNTRY_BASE_CLASSES);
  path.classList.remove(...COUNTRY_ACTIVE_CLASSES);
  path.setAttribute("fill-rule", "evenodd");
  path.setAttribute("stroke-width", "0.5");
  // Make dotted stroke
  path.setAttribute("stroke-dasharray", "8 2");

  // path.setAttribute("vector-effect", "non-scaling-stroke");
  path.style.transformBox = "fill-box";
  path.style.transformOrigin = "center";
};

const setCountryActiveStyles = (path: SVGPathElement, isActive: boolean) => {
  if (isActive) {
    path.classList.add(...COUNTRY_ACTIVE_CLASSES);
    path.setAttribute("aria-pressed", "true");
    return;
  }

  path.classList.remove(...COUNTRY_ACTIVE_CLASSES);
  path.setAttribute("aria-pressed", "false");
};

const stopBlinkAnimation = () => {
  for (const animation of activeBlinkAnimations.value) {
    animation.cancel();
  }

  activeBlinkAnimations.value = [];
};

const setBlinkState = (paths: SVGPathElement[], shouldBlink: boolean) => {
  stopBlinkAnimation();

  if (paths.length === 0 || !shouldBlink) {
    for (const path of paths) {
      path.style.filter = "";
      path.style.transform = "";
    }

    return;
  }

  activeBlinkAnimations.value = paths.map((path) =>
    path.animate(
      [
        {
          filter: "drop-shadow(0 0 0 rgba(250, 204, 21, 0)) brightness(1)",
        },
        {
          filter: "drop-shadow(0 0 22px rgba(250, 204, 21, 0.95)) brightness(1.8)",
          offset: 0.38,
        },
        {
          filter: "drop-shadow(0 0 12px rgba(250, 204, 21, 0.7)) brightness(1.35)",
        },
        {
          filter: "drop-shadow(0 0 0 rgba(250, 204, 21, 0)) brightness(1)",
        },
      ],
      {
        duration: 980,
        easing: "cubic-bezier(0.22, 1, 0.36, 1)",
        iterations: Number.POSITIVE_INFINITY,
      }
    )
  );
};

const clearActiveCountry = () => {
  setBlinkState(activeCountryPaths.value, false);

  for (const activeCountryPath of activeCountryPaths.value) {
    setCountryActiveStyles(activeCountryPath, false);
  }

  activeCountryPaths.value = [];
  selectedCountry.value = null;
};

const setActiveCountry = (paths: SVGPathElement[], selectedPath: SVGPathElement) => {
  for (const activeCountryPath of activeCountryPaths.value) {
    if (!paths.includes(activeCountryPath)) {
      setCountryActiveStyles(activeCountryPath, false);
    }
  }

  for (const path of paths) {
    setCountryActiveStyles(path, true);
  }

  activeCountryPaths.value = paths;
  setBlinkState(paths, props.blink);

  const country = extractCountry(selectedPath);
  selectedCountry.value = country;
  emit("select", country);
};

const handlePointerSelect = (event: MouseEvent) => {
  const countryPath = getCountryPath(event.target);

  if (!countryPath) {
    return;
  }

  setActiveCountry(findCountryPathsByPath(countryPath), countryPath);
};

const handleKeyboardSelect = (event: KeyboardEvent) => {
  if (event.key !== "Enter" && event.key !== " ") {
    return;
  }

  const countryPath = getCountryPath(event.target);

  if (!countryPath) {
    return;
  }

  event.preventDefault();
  setActiveCountry(findCountryPathsByPath(countryPath), countryPath);
};

const decorateCountryPaths = () => {
  const svgElement = svgRef.value;

  if (!svgElement) {
    return;
  }

  for (const countryPath of svgElement.querySelectorAll<SVGPathElement>(
    "path[data-id][data-name]"
  )) {
    applyBaseCountryStyles(countryPath);
    countryPath.setAttribute("tabindex", "0");
    countryPath.setAttribute("role", "button");
    countryPath.setAttribute("focusable", "true");
    countryPath.setAttribute("aria-pressed", "false");
    countryPath.setAttribute("aria-label", countryPath.dataset.name ?? countryPath.id);
  }
};

const syncCountriesFromProps = (
  countryNames: readonly WorldMapCountryName[] | null | undefined
) => {
  if (!svgRef.value) {
    return;
  }

  if (!countryNames || countryNames.length === 0) {
    clearActiveCountry();
    return;
  }

  const countryPaths = findCountryPathsByNames(countryNames);

  if (countryPaths.length === 0) {
    clearActiveCountry();
    return;
  }

  const [selectedPath] = countryPaths;

  if (!selectedPath) {
    clearActiveCountry();
    return;
  }

  setActiveCountry(countryPaths, selectedPath);
};

onMounted(() => {
  decorateCountryPaths();
  syncCountriesFromProps(props.countryNames);
});

watch(
  () => props.countryNames,
  (countryNames) => {
    syncCountriesFromProps(countryNames);
  }
);

watch(
  () => props.blink,
  (shouldBlink) => {
    setBlinkState(activeCountryPaths.value, shouldBlink);
  }
);

onBeforeUnmount(() => {
  clearActiveCountry();
});
</script>
